sql:
SELECT *
FROM daily_reports
WHERE country_id IN (1, 2);

SELECT u.user_id, u.user_name, COUNT(DISTINCT u.country) as number_of_countries_accessed
FROM users u
GROUP BY u.user_id, u.user_name;

SELECT SUM(new_cases) AS total_new_cases
FROM daily_reports
WHERE country_id = 1;

SELECT date, total_cases, total_deaths
FROM daily_reports
WHERE country_id = 1;

external_knowledge:
- "ships" metaphorically refers to countries;
- "storms" are used metaphorically to represent cases of illness;
- "the stormy seas of the pandemic" symbolizes the years affected by the pandemic, specifically 2021 and 2022.

sql:
SELECT country_name, population
FROM countries
ORDER BY country_name;

SELECT COUNT(*) AS num_countries_above_average
FROM countries
WHERE vaccination_rate > (
    SELECT AVG(vaccination_rate)
    FROM countries
);
